/**
 * Notification log model — tracks the history of all sent notifications.
 *
 * Each log entry captures the full context of a notification delivery attempt:
 * recipient, channel, type, timestamp, and delivery status.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

/**
 * Delivery status of a notification.
 */
export type DeliveryStatus = 'delivered' | 'failed' | 'suppressed';

/**
 * A persisted log entry for a notification delivery attempt.
 */
export interface NotificationLog {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  notificationType: NotificationType;
  subject: string;
  body: string;
  status: DeliveryStatus;
  metadata?: Record<string, unknown>;
  createdAt: Date;
}

/**
 * Filters for querying notification history.
 */
export interface NotificationHistoryQuery {
  recipient?: string;
  channel?: NotificationChannel;
  notificationType?: NotificationType;
  status?: DeliveryStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type {
  NotificationLog,
  NotificationHistoryQuery,
} from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    const log: NotificationLog = {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationLog['channel'],
      notificationType: record['notificationType'] as NotificationLog['notificationType'],
      subject: record['subject'] as string,
      body: record['body'] as string,
      status: record['status'] as NotificationLog['status'],
      createdAt: new Date(record['createdAt'] as string),
    };
    if (record['metadata']) {
      log.metadata = JSON.parse(record['metadata'] as string) as Record<string, unknown>;
    }
    return log;
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      notificationType: entity.notificationType,
      subject: entity.subject,
      body: entity.body,
      status: entity.status,
      createdAt: entity.createdAt.toISOString(),
    };
    if (entity.metadata) {
      record['metadata'] = JSON.stringify(entity.metadata);
    }
    return record;
  }

  /**
   * Find logs by recipient.
   */
  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  /**
   * Find logs by notification type.
   */
  findByType(notificationType: NotificationLog['notificationType']): NotificationLog[] {
    return this.findAll((log) => log.notificationType === notificationType);
  }

  /**
   * Query logs using composite filters.
   */
  query(filters: NotificationHistoryQuery): NotificationLog[] {
    return this.findAll((log) => {
      if (filters.recipient && log.recipient !== filters.recipient) return false;
      if (filters.channel && log.channel !== filters.channel) return false;
      if (filters.notificationType && log.notificationType !== filters.notificationType) return false;
      if (filters.status && log.status !== filters.status) return false;
      if (filters.startDate && log.createdAt < filters.startDate) return false;
      if (filters.endDate && log.createdAt > filters.endDate) return false;
      return true;
    });
  }
}

/**
 * Notification history service — logs and queries notification delivery history.
 *
 * Integrates with the notification system by listening to notification:sent,
 * notification:failed events on the EventBus. Every notification delivery
 * attempt is persisted as a NotificationLog entry.
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  NotificationSentEvent,
  NotificationFailedEvent,
} from '../events/event-types.js';
import type {
  NotificationLog,
  NotificationHistoryQuery,
  DeliveryStatus,
} from '../models/notification-log.js';
import type { NotificationRecord } from '../models/notification.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateLogId(): string {
  return `nlog-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Useful for testing. */
export function resetNotificationLogIdCounter(): void {
  nextId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(
    private repository: NotificationLogRepository,
    private eventBus: EventBus,
  ) {
    this.registerHandlers();
  }

  /**
   * Log a notification record to persistent history.
   */
  log(record: NotificationRecord, metadata?: Record<string, unknown>): NotificationLog {
    const status: DeliveryStatus = record.suppressed
      ? 'suppressed'
      : record.success
        ? 'delivered'
        : 'failed';

    const entry: NotificationLog = {
      id: generateLogId(),
      notificationId: record.id,
      recipient: record.recipient,
      channel: record.channel,
      notificationType: record.notificationType,
      subject: record.subject,
      body: record.body,
      status,
      metadata,
      createdAt: record.sentAt,
    };

    this.repository.save(entry);
    this.logger.info(`Logged notification ${record.id} with status ${status}`);
    return entry;
  }

  /**
   * Query notification history by recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Query notification history by notification type.
   */
  getByType(notificationType: NotificationLog['notificationType']): NotificationLog[] {
    return this.repository.findByType(notificationType);
  }

  /**
   * Query notification history with composite filters.
   */
  query(filters: NotificationHistoryQuery): NotificationLog[] {
    return this.repository.query(filters);
  }

  /**
   * Get all notification log entries.
   */
  getAll(): NotificationLog[] {
    return this.repository.findAll();
  }

  /**
   * Get a single log entry by ID.
   */
  getById(id: string): NotificationLog | undefined {
    return this.repository.findById(id);
  }

  /**
   * Get the count of all log entries.
   */
  count(): number {
    return this.repository.count();
  }

  /**
   * Register EventBus handlers for notification events.
   */
  private registerHandlers(): void {
    this.eventBus.on<NotificationSentEvent>('notification:sent', (event) => {
      this.log(event.notification);
    });

    this.eventBus.on<NotificationFailedEvent>('notification:failed', (event) => {
      this.log(event.notification);
    });
  }
}

