import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationRecord } from '../../src/models/notification.js';
import type { NotificationPayload } from '../../src/models/notification.js';
import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';

function makeRecord(overrides?: Partial<NotificationRecord>): NotificationRecord {
  return {
    id: 'notif-0001',
    recipient: 'alice@example.com',
    channel: 'email',
    notificationType: 'order-confirmation',
    subject: 'Order Confirmed',
    body: 'Your order has been placed.',
    success: true,
    suppressed: false,
    sentAt: new Date('2026-01-15T10:00:00Z'),
    ...overrides,
  };
}

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    channel: 'email',
    notificationType: 'order-confirmation',
    recipient: 'alice@example.com',
    subject: 'Order Confirmed',
    body: 'Your order has been placed.',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let eventBus: EventBus;
  let repo: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    repo = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repo, eventBus);
    resetNotificationLogIdCounter();
    resetNotificationIdCounter();
  });

  describe('log', () => {
    it('should log a successful notification', () => {
      const record = makeRecord();
      const entry = historyService.log(record);

      expect(entry.id).toBe('nlog-0001');
      expect(entry.notificationId).toBe('notif-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.notificationType).toBe('order-confirmation');
      expect(entry.subject).toBe('Order Confirmed');
      expect(entry.status).toBe('delivered');
      expect(entry.createdAt).toEqual(new Date('2026-01-15T10:00:00Z'));
    });

    it('should log a failed notification', () => {
      const record = makeRecord({ success: false });
      const entry = historyService.log(record);

      expect(entry.status).toBe('failed');
    });

    it('should log a suppressed notification', () => {
      const record = makeRecord({ success: false, suppressed: true });
      const entry = historyService.log(record);

      expect(entry.status).toBe('suppressed');
    });

    it('should store metadata when provided', () => {
      const record = makeRecord();
      const entry = historyService.log(record, { orderId: 'order-1' });

      expect(entry.metadata).toEqual({ orderId: 'order-1' });
    });

    it('should generate sequential IDs', () => {
      const e1 = historyService.log(makeRecord({ id: 'notif-0001' }));
      const e2 = historyService.log(makeRecord({ id: 'notif-0002' }));

      expect(e1.id).toBe('nlog-0001');
      expect(e2.id).toBe('nlog-0002');
    });

    it('should persist entries in the repository', () => {
      historyService.log(makeRecord());
      historyService.log(makeRecord({ id: 'notif-0002', recipient: 'bob@example.com' }));

      expect(historyService.count()).toBe(2);
    });
  });

  describe('query methods', () => {
    beforeEach(() => {
      historyService.log(
        makeRecord({ id: 'notif-0001', recipient: 'alice@example.com', notificationType: 'order-confirmation' }),
      );
      historyService.log(
        makeRecord({ id: 'notif-0002', recipient: 'bob@example.com', notificationType: 'user-welcome', sentAt: new Date('2026-01-16T10:00:00Z') }),
      );
      historyService.log(
        makeRecord({ id: 'notif-0003', recipient: 'alice@example.com', notificationType: 'system-alert', channel: 'webhook', sentAt: new Date('2026-01-17T10:00:00Z') }),
      );
    });

    it('should query by recipient', () => {
      const results = historyService.getByRecipient('alice@example.com');
      expect(results).toHaveLength(2);
      expect(results.every((r) => r.recipient === 'alice@example.com')).toBe(true);
    });

    it('should query by notification type', () => {
      const results = historyService.getByType('order-confirmation');
      expect(results).toHaveLength(1);
      expect(results[0].notificationType).toBe('order-confirmation');
    });

    it('should query with composite filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        channel: 'email',
      });
      expect(results).toHaveLength(1);
      expect(results[0].notificationType).toBe('order-confirmation');
    });

    it('should query by date range', () => {
      const results = historyService.query({
        startDate: new Date('2026-01-16T00:00:00Z'),
        endDate: new Date('2026-01-16T23:59:59Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0].recipient).toBe('bob@example.com');
    });

    it('should query by status', () => {
      historyService.log(
        makeRecord({ id: 'notif-0004', success: false }),
      );
      const failed = historyService.query({ status: 'failed' });
      expect(failed).toHaveLength(1);
      expect(failed[0].status).toBe('failed');
    });

    it('should return all entries', () => {
      expect(historyService.getAll()).toHaveLength(3);
    });

    it('should get entry by ID', () => {
      const entry = historyService.getById('nlog-0001');
      expect(entry).toBeDefined();
      expect(entry!.notificationId).toBe('notif-0001');
    });

    it('should return undefined for non-existent ID', () => {
      expect(historyService.getById('nlog-9999')).toBeUndefined();
    });

    it('should return empty array when no matches', () => {
      const results = historyService.getByRecipient('nobody@example.com');
      expect(results).toHaveLength(0);
    });
  });

  describe('EventBus integration', () => {
    it('should log on notification:sent event', async () => {
      const record = makeRecord();
      await eventBus.emit({
        type: 'notification:sent',
        notification: record,
        timestamp: new Date(),
      });

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0].status).toBe('delivered');
      expect(logs[0].notificationId).toBe('notif-0001');
    });

    it('should log on notification:failed event', async () => {
      const record = makeRecord({ success: false });
      await eventBus.emit({
        type: 'notification:failed',
        notification: record,
        error: 'Transport error',
        timestamp: new Date(),
      });

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0].status).toBe('failed');
    });
  });

  describe('end-to-end with NotificationService', () => {
    let notificationService: NotificationService;
    let emailAdapter: EmailAdapter;

    beforeEach(() => {
      notificationService = new NotificationService(eventBus);
      emailAdapter = new EmailAdapter();
      notificationService.registerAdapter(emailAdapter);
      notificationService.setHistoryService(historyService);
    });

    it('should log successful notification delivery', async () => {
      await notificationService.send(makePayload());

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0].status).toBe('delivered');
      expect(logs[0].recipient).toBe('alice@example.com');
      expect(logs[0].channel).toBe('email');
    });

    it('should log failed notification when no adapter registered', async () => {
      const service = new NotificationService(eventBus);
      // Re-create history service to listen on same event bus
      const freshHistory = new NotificationHistoryService(
        new NotificationLogRepository(db),
        eventBus,
      );
      resetNotificationLogIdCounter();

      await service.send(makePayload({ channel: 'webhook' }));

      const logs = freshHistory.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0].status).toBe('failed');
    });

    it('should log suppressed notifications via direct integration', async () => {
      const prefsDb = new Database();
      const prefsRepo = new PreferencesRepository(prefsDb);
      const prefsService = new PreferencesService(prefsRepo);
      resetPreferencesIdCounter();

      prefsService.updateEmailPreferences('user-1', { enabled: false });
      notificationService.setPreferencesService(prefsService);

      await notificationService.send(makePayload());

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0].status).toBe('suppressed');
    });

    it('should accumulate history across multiple sends', async () => {
      await notificationService.send(makePayload());
      await notificationService.send(makePayload({
        recipient: 'bob@example.com',
        notificationType: 'user-welcome',
        subject: 'Welcome',
        body: 'Welcome Bob!',
      }));

      expect(historyService.count()).toBe(2);
      const aliceLogs = historyService.getByRecipient('alice@example.com');
      const bobLogs = historyService.getByRecipient('bob@example.com');
      expect(aliceLogs).toHaveLength(1);
      expect(bobLogs).toHaveLength(1);
    });
  });
});

